    private static final String STATE_LEVEL_GROUP = "stream-state-updater-metrics";

    private static final String IDLE_RATIO_DESCRIPTION = WINDOWED_RATIO_DESCRIPTION_PREFIX + THREAD_TIME_UNIT_DESCRIPTION + "being idle";
