   206→            throw new IllegalStateException("Attempted to create an active task while we already own its standby: " + taskId);
   207→        }
   208→
   209→        activeTasksPerId.put(taskId, task);
   210→        pendingActiveTasksToCreate.remove(taskId);
   211→        for (final TopicPartition topicPartition : task.inputPartitions()) {
   212→            activeTasksPerPartition.put(topicPartition, task);
   213→        }
   214→    }
   215→
   216→    @Override
   217→    public synchronized void addStandbyTask(final StandbyTask task) {
   218→        final TaskId taskId = task.id();
   219→
   220→        if (standbyTasksPerId.containsKey(taskId)) {
   221→            throw new IllegalStateException("Attempted to create an standby task that we already own: " + taskId);
   222→        }
   223→
   224→        if (activeTasksPerId.containsKey(taskId)) {
   225→            throw new IllegalStateException("Attempted to create an standby task while we already own its active: " + taskId);
   226→        }
   227→
   228→        standbyTasksPerId.put(taskId, task);
   229→    }
   230→
   231→    @Override
   232→    public void addFailedTask(final Task task) {
   233→        failedTaskIds.add(task.id());
   234→        addTask(task);
   235→    }
   236→
   237→    @Override
   238→    public synchronized void removeTask(final Task taskToRemove) {
   239→        final TaskId taskId = taskToRemove.id();
   240→
