   242→            throw new IllegalStateException("Attempted to remove a task that is not closed or suspended: " + taskId);
   243→        }
   244→
   245→        if (pendingTasksToClose.contains(taskToRemove)) {
   246→            pendingTasksToClose.remove(taskToRemove);
   247→        } else if (taskToRemove.isActive()) {
   248→            if (activeTasksPerId.remove(taskId) == null) {
   249→                throw new IllegalArgumentException("Attempted to remove an active task that is not owned: " + taskId);
   250→            }
   251→            removePartitionsForActiveTask(taskId);
   252→        } else {
   253→            if (standbyTasksPerId.remove(taskId) == null) {
   254→                throw new IllegalArgumentException("Attempted to remove a standby task that is not owned: " + taskId);
   255→            }
   256→        }
   257→        failedTaskIds.remove(taskId);
   258→    }
   259→
   260→    @Override
   261→    public synchronized void replaceStandbyWithActive(final StreamTask activeTask) {
   262→        final TaskId taskId = activeTask.id();
   263→        if (standbyTasksPerId.remove(taskId) == null) {
   264→            throw new IllegalStateException("Attempted to convert unknown standby task to stream task: " + taskId);
   265→        }
   266→
   267→        activeTasksPerId.put(activeTask.id(), activeTask);
   268→        for (final TopicPartition topicPartition : activeTask.inputPartitions()) {
   269→            activeTasksPerPartition.put(topicPartition, activeTask);
   270→        }
   271→    }
   272→
   273→    @Override
   274→    public boolean updateActiveTaskInputPartitions(final StreamTask task, final Set<TopicPartition> topicPartitions) {
