   291→            .filter(e -> e.getValue().id().equals(taskId))
   292→            .map(Map.Entry::getKey)
   293→            .collect(Collectors.toSet());
   294→        toBeRemoved.forEach(activeTasksPerPartition::remove);
   295→    }
   296→
   297→    @Override
   298→    public synchronized void clear() {
   299→        pendingTasksToInit.clear();
   300→        pendingTasksToClose.clear();
   301→        pendingActiveTasksToCreate.clear();
   302→        pendingStandbyTasksToCreate.clear();
   303→        activeTasksPerId.clear();
   304→        standbyTasksPerId.clear();
   305→        activeTasksPerPartition.clear();
   306→        failedTaskIds.clear();
   307→    }
   308→
   309→    @Override
   310→    public StreamTask activeInitializedTasksForInputPartition(final TopicPartition partition) {
   311→        return activeTasksPerPartition.get(partition);
   312→    }
   313→
   314→    private synchronized Task getTask(final TaskId taskId) {
   315→        if (activeTasksPerId.containsKey(taskId)) {
   316→            return activeTasksPerId.get(taskId);
   317→        }
   318→        if (standbyTasksPerId.containsKey(taskId)) {
   319→            return standbyTasksPerId.get(taskId);
   320→        }
   321→        return null;
   322→    }
   323→
   324→    @Override
   325→    public Task initializedTask(final TaskId taskId) {
   326→        final Task task = getTask(taskId);
   327→
   328→        if (task != null)
   329→            return task;
   330→        else
   331→            throw new IllegalStateException("Task unknown: " + taskId);
   332→    }
   333→
   334→    @Override
   335→    public Collection<Task> initializedTasks(final Collection<TaskId> taskIds) {
   336→        final Set<Task> tasks = new HashSet<>();
   337→        for (final TaskId taskId : taskIds) {
   338→            tasks.add(initializedTask(taskId));
   339→        }
   340→        return tasks;
   341→    }
   342→
   343→    @Override
   344→    public synchronized Collection<TaskId> activeInitializedTaskIds() {
   345→        return Collections.unmodifiableCollection(activeTasksPerId.keySet());
   346→    }
   347→
   348→    @Override
   349→    public synchronized Collection<StreamTask> activeInitializedTasks() {
   350→        return Collections.unmodifiableCollection(activeTasksPerId.values());
   351→    }
   352→
   353→    @Override
   354→    public synchronized Collection<StandbyTask> standbyInitializedTasks() {
   355→        return Collections.unmodifiableCollection(standbyTasksPerId.values());
   356→    }
   357→
   358→    /**
   359→     * All tasks returned by any of the getters are read-only and should NOT be modified;
   360→     * and the returned task could be modified by other threads concurrently
   361→     */
   362→    @Override
   363→    public synchronized Set<Task> allInitializedTasks() {
