            }
        }
    }

    @Override
    public void addStandbyTasks(final Collection<StandbyTask> newTasks) {
        if (!newTasks.isEmpty()) {
            for (final StandbyTask standbyTask : newTasks) {
                addStandbyTask(standbyTask);
            }
        }
