    public Collection<Task> initializedTasks(final Collection<TaskId> taskIds) {
        final Set<Task> tasks = new HashSet<>();
        for (final TaskId taskId : taskIds) {
            tasks.add(initializedTask(taskId));
        }
        return tasks;
