80→    private ProcessorTopology globalTopology;
    81→    private final Map<String, StateStore> globalStateStores = new HashMap<>();
    82→    private final Set<String> allInputTopics = new HashSet<>();
    83→    private final Map<String, Long> threadVersions = new ConcurrentHashMap<>();
    84→    private final List<TopologyLifecycleObserver> lifecycleObservers = new ArrayList<>();
    85→
    86→    public static class TopologyVersion {
    87→        public AtomicLong topologyVersion = new AtomicLong(0L); // the local topology version
    88→        public ReentrantLock topologyLock = new ReentrantLock();
    89→        public Condition topologyCV = topologyLock.newCondition();
    90→        public List<TopologyVersionListener> activeTopologyUpdateListeners = new LinkedList<>();
    91→    }
    92→
    93→    public static class TopologyVersionListener {
    94→        final long topologyVersion; // the (minimum) version to wait for these threads to cross
    95→        final KafkaFutureImpl<Void> future; // the future waiting on all threads to be updated
    96→
    97→        public TopologyVersionListener(final long topologyVersion, final KafkaFutureImpl<Void> future) {
    98→            this.topologyVersion = topologyVersion;
    99→            this.future = future;
   100→        }
   101→    }
   102→
   103→    public interface TopologyLifecycleObserver {
   104→        void onTopologyChange(long newVersion, Set<String> activeTopologies);
   105→    }
   106→
   107→    public TopologyMetadata(final InternalTopologyBuilder builder,
   108→                            final StreamsConfig config) {
   109→        this.version = new TopologyVersion();
   110→        this.processingMode = StreamsConfigUtils.processingMode(config);
   111→        this.config = config;
   112→        this.log = LoggerFactory.getLogger(getClass());
   113→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
   114→
   115→        builders = new ConcurrentSkipListMap<>();
   116→        if (builder.hasNamedTopology()) {
   117→            builders.put(builder.topologyName(), builder);
   118→        } else {
   119→            builders.put(UNNAMED_TOPOLOGY, builder);
   120→        }
   121→        this.taskExecutionMetadata = new TaskExecutionMetadata(builders.keySet(), pausedTopologies, processingMode);
   122→    }
   123→
   124→    public TopologyMetadata(final ConcurrentNavigableMap<String, InternalTopologyBuilder> builders,
   125→                            final StreamsConfig config) {
   126→        this.version = new TopologyVersion();
   127→        this.processingMode = StreamsConfigUtils.processingMode(config);
   128→        this.config = config;
   129→        this.log = LoggerFactory.getLogger(getClass());
   130→        this.pausedTopologies = ConcurrentHashMap.newKeySet();
   131→
   132→        this.builders = builders;
   133→        if (builders.isEmpty()) {
   134→            log.info("Created an empty KafkaStreams app with no topology");
   135→        }
   136→        this.taskExecutionMetadata = new TaskExecutionMetadata(builders.keySet(), pausedTopologies, processingMode);
   137→    }
   138→
   139→    // Need to (re)set the log here to pick up the `processId` part of the clientId in the prefix
   140→    public void setLog(final LogContext logContext) {
   141→        log = logContext.logger(getClass());
   142→    }
   143→    
   144→    public ProcessingMode processingMode() {
   145→        return processingMode;
   146→    }
   147→
   148→    public long topologyVersion() {
   149→        return version.topologyVersion.get();
   150→    }
   151→
   152→    private void lock() {
   153→        version.topologyLock.lock();
   154→    }
   155→
   156→    private void unlock() {
   157→        version.topologyLock.unlock();
   158→    }
   159→
   160→    public Collection<String> sourceTopicsForTopology(final String name) {
   161→        return builders.get(name).fullSourceTopicNames();
   162→    }
   163→
   164→    public boolean needsUpdate(final String threadName) {
   165→        return threadVersions.get(threadName) < topologyVersion();
   166→    }
   167→
   168→    public void registerThread(final String threadName) {
   169→        threadVersions.put(threadName, 0L);
   170→    }
   171→
   172→    public void unregisterThread(final String threadName) {
   173→        threadVersions.remove(threadName);
   174→        maybeNotifyTopologyVersionListeners();
   175→    }
   176→
   177→    public void registerLifecycleObserver(final TopologyLifecycleObserver observer) {
   178→        lock();
   179→        try {
   180→            lifecycleObservers.add(observer);
   181→        } finally {
   182→            unlock();
   183→        }
   184→    }
   185→
   186→    public TaskExecutionMetadata taskExecutionMetadata() {
   187→        return taskExecutionMetadata;
   188→    }
   189→
   190→    public void executeTopologyUpdatesAndBumpThreadVersion(final Consumer<Set<String>> handleTopologyAdditions,
   191→                                                           final Consumer<Set<String>> handleTopologyRemovals) {
   192→        try {
   193→            version.topologyLock.lock();
   194→            final long latestTopologyVersion = topologyVersion();
   195→            handleTopologyAdditions.accept(namedTopologiesView());
   196→            handleTopologyRemovals.accept(namedTopologiesView());
   197→            threadVersions.put(Thread.currentThread().getName(), latestTopologyVersion);
   198→        } finally {
   199→            version.topologyLock.unlock();
   200→        }
   201→    }
   202→
   203→    public void maybeNotifyTopologyVersionListeners() {
   204→        try {
   205→            lock();
   206→            final long minThreadVersion = minimumThreadVersion();
   207→            final Iterator<TopologyVersionListener> iterator = version.activeTopologyUpdateListeners.listIterator();
   208→            TopologyVersionListener topologyVersionListener;
   209→            while (iterator.hasNext()) {
   210→                topologyVersionListener = iterator.next();
   211→                final long topologyVersionWaitersVersion = topologyVersionListener.topologyVersion;
   212→                if (minThreadVersion >= topologyVersionWaitersVersion) {
   213→                    topologyVersionListener.future.complete(null);
   214→                    iterator.remove();
   215→                    log.info("All threads are now on topology version {}", topologyVersionListener.topologyVersion);
   216→                }
   217→            }
   218→        } finally {
   219→            unlock();
   220→        }
   221→    }
   222→
   223→    // Return the minimum version across all live threads, or Long.MAX_VALUE if there are no threads running
   224→    private long minimumThreadVersion() {
   225→        final Optional<Long> minVersion = threadVersions.values().stream().min(Long::compare);
   226→        return minVersion.orElse(Long.MAX_VALUE);
   227→    }
   228→
   229→    public void wakeupThreads() {
   230→        try {
   231→            lock();
   232→            version.topologyCV.signalAll();
   233→        } finally {
   234→            unlock();
   235→        }
   236→    }
   237→
   238→    private void notifyLifecycleObservers() {
   239→        final long currentVersion = version.topologyVersion.get();
   240→        final Set<String> activeTopologies = namedTopologiesView();
   241→        for (final TopologyLifecycleObserver observer : lifecycleObservers) {
   242→            try {
   243→                observer.onTopologyChange(currentVersion, activeTopologies);
   244→            } catch (final Exception e) {
   245→                log.warn("Topology lifecycle observer threw exception", e);
   246→            }
   247→        }
   248→    }
   249→
   250→    public void maybeWaitForNonEmptyTopology(final Supplier<StreamThread.State> threadState) {
   251→        if (isEmpty() && threadState.get().isAlive()) {
   252→            try {
   253→                lock();
   254→                while (isEmpty() && threadState.get().isAlive()) {
   255→                    try {
   256→                        log.debug("Detected that the topology is currently empty, waiting for something to process");
   257→                        version.topologyCV.await();
   258→                    } catch (final InterruptedException e) {
   259→                        log.error("StreamThread was interrupted while waiting on empty topology", e);
   260→                    }
   261→                }
   262→            } finally {
   263→                unlock();
   264→            }
   265→        }
   266→    }
   267→
   268→    /**
   269→     * Adds the topology and registers a future that listens for all threads on the older version to see the update
   270→     */
   271→    public void registerAndBuildNewTopology(final KafkaFutureImpl<Void> future, final InternalTopologyBuilder newTopologyBuilder) {
   272→        try {
   273→            lock();
   274→            buildAndVerifyTopology(newTopologyBuilder);
   275→            log.info("New NamedTopology {} passed validation and will be added, old topology version is {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
   276→            version.topologyVersion.incrementAndGet();
   277→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), future));
