299→    public boolean isStartingRunningOrPartitionAssigned() {
300→        synchronized (stateLock) {
301→            return state.equals(State.RUNNING) || state.equals(State.STARTING) || state.equals(State.PARTITIONS_ASSIGNED);
302→        }
303→    }
