package org.apache.kafka.streams.processor.internals;

import org.apache.kafka.streams.processor.internals.TopologyMetadata.TopologyLifecycleObserver;

import java.util.Set;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.locks.ReentrantReadWriteLock;

/**
 * Fray test for the deadlock between snapshotLock and topologyLock.
 *
 * Before the fix, the following cycle existed:
 *   StateUpdaterThread: snapshotLock(write) -> topologyLock
 *   User thread:        topologyLock -> snapshotLock(write)  (via lifecycle observer)
 *
 * Fray systematically explores thread interleavings to detect this.
 */
public class StateUpdaterDeadlockTest {

    public static void main(String[] args) throws Exception {
        // Simulate the two lock objects involved in the deadlock
        final ReentrantReadWriteLock snapshotLock = new ReentrantReadWriteLock();
        final TopologyMetadata.TopologyVersion version = new TopologyMetadata.TopologyVersion();

        // Register a lifecycle observer that acquires snapshotLock (like KafkaStreams does)
        // This simulates KafkaStreams.refreshRestorationState() -> invalidateRestorationSnapshot()
        final Object kafkaStreamsMonitor = new Object();

        final CountDownLatch ready = new CountDownLatch(2);

        // Thread 1: Simulates StateUpdaterThread.maybeRefreshRestorationSnapshot()
        // Original (buggy) order: snapshotLock(write) -> topologyLock
        // Fixed order: snapshotLock(write), release, then topologyLock
        final Thread stateUpdaterThread = new Thread(() -> {
            ready.countDown();
            try { ready.await(); } catch (InterruptedException e) { return; }

            // This is the fixed code path: acquire snapshotLock, update snapshot, release,
            // then acquire topologyLock via maybeNotifyTopologyVersionListeners
            snapshotLock.writeLock().lock();
            try {
                // simulate updateRestorationSnapshot
            } finally {
                snapshotLock.writeLock().unlock();
            }
            // After fix: topologyLock acquired AFTER snapshotLock is released
            version.topologyLock.lock();
            try {
                // simulate maybeNotifyTopologyVersionListeners
            } finally {
                version.topologyLock.unlock();
            }
        }, "state-updater-thread");

        // Thread 2: Simulates registerAndBuildNewTopology -> notifyLifecycleObservers
        // -> KafkaStreams.refreshRestorationState -> invalidateRestorationSnapshot
        // Order: topologyLock -> kafkaStreamsMonitor -> snapshotLock(write)
        final Thread topologyUpdateThread = new Thread(() -> {
            ready.countDown();
            try { ready.await(); } catch (InterruptedException e) { return; }

            version.topologyLock.lock();
            try {
                // simulate notifyLifecycleObservers -> observer.onTopologyChange
                synchronized (kafkaStreamsMonitor) {
                    // simulate refreshRestorationState -> invalidateRestorationSnapshot
                    snapshotLock.writeLock().lock();
                    try {
                        // simulate updateRestorationSnapshot
                    } finally {
                        snapshotLock.writeLock().unlock();
                    }
                }
            } finally {
                version.topologyLock.unlock();
            }
        }, "topology-update-thread");

        stateUpdaterThread.start();
        topologyUpdateThread.start();

        stateUpdaterThread.join(10_000);
        topologyUpdateThread.join(10_000);

        if (stateUpdaterThread.isAlive() || topologyUpdateThread.isAlive()) {
            throw new RuntimeException("Deadlock detected: threads did not complete");
        }
    }
}

